3107 Instruction *InstCombinerImpl::visitReturnInst(ReturnInst &RI) {
3108   Value *RetVal = RI.getReturnValue();
3109   if (!RetVal || !AttributeFuncs::isNoFPClassCompatibleType(RetVal->getType()))
3110     return nullptr;
3111 
3112   Function *F = RI.getFunction();
3113   FPClassTest ReturnClass = F->getAttributes().getRetNoFPClass();
3114   if (ReturnClass == fcNone)
3115     return nullptr;
3116 
3117   KnownFPClass KnownClass;
3118   Value *Simplified =
3119       SimplifyDemandedUseFPClass(RetVal, ~ReturnClass, KnownClass, 0, &RI);
3120   if (!Simplified)
3121     return nullptr;
3122 
3123   return ReturnInst::Create(RI.getContext(), Simplified);
3124 }
