3247 void InstCombinerImpl::handlePotentiallyDeadSuccessors(BasicBlock *BB,
3248                                                        BasicBlock *LiveSucc) {
3249   SmallVector<BasicBlock *> Worklist;
3250   for (BasicBlock *Succ : successors(BB)) {
3251     // The live successor isn't dead.
3252     if (Succ == LiveSucc)
3253       continue;
3254 
3255     addDeadEdge(BB, Succ, Worklist);
3256   }
3257 
3258   handlePotentiallyDeadBlocks(Worklist);
3259 }
